export function WildNCulture() {
  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <PageTitle title="Wild n' Culture" />
      <h1 className="text-3xl font-bold text-white mb-6">Wild n' Culture</h1>
      <p className="text-gray-300">Details about Wild n' Culture event coming soon!</p>
    </div>
  );
}
